@* Displays a single task with move buttons *@

<div class="card mb-2">
    <div class="card-body p-2">
        <h6 class="card-title mb-1">@Task.Title</h6>
        <p class="card-text mb-1 text-muted small">@Task.Assignee</p>
        <span class="badge @PriorityClass me-1">@Task.Priority</span>
        <span class="text-muted small">@Task.DueDate.ToString("MMM dd")</span>
        <div class="mt-2 d-flex gap-1">
            @if (ShowMoveLeft)
            {
                <button class="btn btn-outline-secondary btn-sm" @onclick="OnMoveLeft" disabled="@IsMoving">
                    &larr; Move Left
                </button>
            }
            @if (ShowMoveRight)
            {
                <button class="btn btn-outline-secondary btn-sm" @onclick="OnMoveRight" disabled="@IsMoving">
                    Move Right &rarr;
                </button>
            }
        </div>
    </div>
</div>

@code {
    [Parameter, EditorRequired] public TaskItem Task { get; set; } = default!;
    [Parameter] public bool ShowMoveLeft { get; set; }
    [Parameter] public bool ShowMoveRight { get; set; }
    [Parameter] public EventCallback<int> OnMoveLeftClicked { get; set; }
    [Parameter] public EventCallback<int> OnMoveRightClicked { get; set; }

    private bool IsMoving;

    private string PriorityClass => Task.Priority switch
    {
        "High" => "bg-danger",
        "Medium" => "bg-warning text-dark",
        "Low" => "bg-success",
        _ => "bg-secondary"
    };

    private async System.Threading.Tasks.Task OnMoveLeft()
    {
        IsMoving = true;
        await OnMoveLeftClicked.InvokeAsync(Task.Id);
        IsMoving = false;
    }

    private async System.Threading.Tasks.Task OnMoveRight()
    {
        IsMoving = true;
        await OnMoveRightClicked.InvokeAsync(Task.Id);
        IsMoving = false;
    }
}

@* Inline form to create a new task within a column *@

<div class="card mb-2 border-primary">
    <div class="card-body p-2">
        <div class="mb-2">
            <input type="text" class="form-control form-control-sm" placeholder="Title" @bind="Title" />
        </div>
        <div class="mb-2">
            <input type="text" class="form-control form-control-sm" placeholder="Assignee" @bind="Assignee" />
        </div>
        <div class="mb-2">
            <select class="form-select form-select-sm" @bind="Priority">
                <option value="">Select priority</option>
                <option value="High">High</option>
                <option value="Medium">Medium</option>
                <option value="Low">Low</option>
            </select>
        </div>
        <div class="mb-2">
            <input type="date" class="form-control form-control-sm" @bind="DueDate" />
        </div>
        <div class="d-flex gap-1">
            <button class="btn btn-primary btn-sm" @onclick="Save" disabled="@IsSaving">Save</button>
            <button class="btn btn-outline-secondary btn-sm" @onclick="Cancel" disabled="@IsSaving">Cancel</button>
        </div>
        @if (!string.IsNullOrEmpty(ValidationError))
        {
            <div class="text-danger small mt-1">@ValidationError</div>
        }
    </div>
</div>

@code {
    [Parameter, EditorRequired] public string Status { get; set; } = default!;
    [Parameter] public EventCallback<(string Title, string Assignee, string Priority, DateTime DueDate)> OnSave { get; set; }
    [Parameter] public EventCallback OnCancel { get; set; }

    private string Title = "";
    private string Assignee = "";
    private string Priority = "";
    private DateTime DueDate = DateTime.Today;
    private bool IsSaving;
    private string? ValidationError;

    private async Task Save()
    {
        ValidationError = null;

        if (string.IsNullOrWhiteSpace(Title) || string.IsNullOrWhiteSpace(Assignee) || string.IsNullOrWhiteSpace(Priority))
        {
            ValidationError = "Title, assignee, and priority are required.";
            return;
        }

        IsSaving = true;
        await OnSave.InvokeAsync((Title.Trim(), Assignee.Trim(), Priority, DueDate));
        IsSaving = false;
    }

    private async Task Cancel()
    {
        await OnCancel.InvokeAsync();
    }
}

@* A single Kanban column showing its tasks and an optional add-task form *@

<div class="col">
    <div class="card h-100">
        <div class="card-header d-flex justify-content-between align-items-center">
            <strong>@ColumnName</strong>
            <span class="badge bg-secondary">@Tasks.Count</span>
        </div>
        <div class="card-body p-2" style="overflow-y: auto;">
            @foreach (var task in Tasks)
            {
                <TaskCard Task="task"
                          ShowMoveLeft="ShowMoveLeft"
                          ShowMoveRight="ShowMoveRight"
                          OnMoveLeftClicked="OnMoveLeftClicked"
                          OnMoveRightClicked="OnMoveRightClicked" />
            }

            @if (ShowAddForm)
            {
                <AddTaskForm Status="@Status"
                             OnSave="OnAddTaskSave"
                             OnCancel="OnAddTaskCancel" />
            }
        </div>
        <div class="card-footer p-2">
            @if (!ShowAddForm)
            {
                <button class="btn btn-outline-primary btn-sm w-100" @onclick="ToggleAddForm">
                    + Add Task
                </button>
            }
        </div>
    </div>
</div>

@code {
    [Parameter, EditorRequired] public string ColumnName { get; set; } = default!;
    [Parameter, EditorRequired] public string Status { get; set; } = default!;
    [Parameter] public List<TaskItem> Tasks { get; set; } = new();
    [Parameter] public bool ShowMoveLeft { get; set; }
    [Parameter] public bool ShowMoveRight { get; set; }
    [Parameter] public EventCallback<int> OnMoveLeftClicked { get; set; }
    [Parameter] public EventCallback<int> OnMoveRightClicked { get; set; }
    [Parameter] public EventCallback<(string Title, string Assignee, string Priority, DateTime DueDate)> OnTaskCreated { get; set; }

    private bool ShowAddForm;

    private void ToggleAddForm() => ShowAddForm = true;

    private async Task OnAddTaskSave((string Title, string Assignee, string Priority, DateTime DueDate) newTask)
    {
        await OnTaskCreated.InvokeAsync(newTask);
        ShowAddForm = false;
    }

    private void OnAddTaskCancel() => ShowAddForm = false;
}

@* Search bar for filtering tasks by title *@

<div class="mb-3">
    <input type="text"
           class="form-control"
           placeholder="Search tasks by title..."
           value="@SearchTerm"
           @oninput="OnInput" />
</div>

@code {
    [Parameter] public string SearchTerm { get; set; } = "";
    [Parameter] public EventCallback<string> SearchTermChanged { get; set; }

    private async Task OnInput(ChangeEventArgs e)
    {
        await SearchTermChanged.InvokeAsync(e.Value?.ToString() ?? "");
    }
}

@page "/board"
@using sv_d32f6a68660b4835ba40ad2c5d15f4f2
@rendermode InteractiveServer
@inject ITaskService TaskService

<PageTitle>Kanban Board</PageTitle>

<h3 class="mb-3">Kanban Board</h3>

@if (isLoading)
{
    <div class="d-flex justify-content-center my-5">
        <div class="spinner-border" role="status">
            <span class="visually-hidden">Loading...</span>
        </div>
    </div>
}
else if (errorMessage is not null)
{
    <div class="alert alert-danger" role="alert">
        <strong>Error:</strong> @errorMessage
        <button class="btn btn-outline-danger btn-sm ms-2" @onclick="LoadTasks">Retry</button>
    </div>
}
else
{
    <BoardStatsBar Tasks="allTasks" />

    <BoardSearchBar SearchTerm="@searchTerm" SearchTermChanged="OnSearchChanged" />

    <div class="row g-3">
        <KanbanColumn ColumnName="To Do"
                      Status="To Do"
                      Tasks="GetFilteredTasks("To Do")"
                      ShowMoveLeft="false"
                      ShowMoveRight="true"
                      OnMoveRightClicked="taskId => MoveTask(taskId, "In Progress")"
                      OnTaskCreated="args => CreateTask(args, "To Do")" />

        <KanbanColumn ColumnName="In Progress"
                      Status="In Progress"
                      Tasks="GetFilteredTasks("In Progress")"
                      ShowMoveLeft="true"
                      ShowMoveRight="true"
                      OnMoveLeftClicked="taskId => MoveTask(taskId, "To Do")"
                      OnMoveRightClicked="taskId => MoveTask(taskId, "Done")"
                      OnTaskCreated="args => CreateTask(args, "In Progress")" />

        <KanbanColumn ColumnName="Done"
                      Status="Done"
                      Tasks="GetFilteredTasks("Done")"
                      ShowMoveLeft="true"
                      ShowMoveRight="false"
                      OnMoveLeftClicked="taskId => MoveTask(taskId, "In Progress")"
                      OnTaskCreated="args => CreateTask(args, "Done")" />
    </div>
}

@code {
    private List<TaskItem> allTasks = new();
    private string searchTerm = "";
    private bool isLoading = true;
    private string? errorMessage;

    private static readonly string[] Columns = { "To Do", "In Progress", "Done" };

    protected override async Task OnInitializedAsync()
    {
        await LoadTasks();
    }

    private async Task LoadTasks()
    {
        isLoading = true;
        errorMessage = null;

        try
        {
            allTasks = await TaskService.GetAllTasksAsync();
        }
        catch (Exception ex)
        {
            errorMessage = ex.Message;
        }
        finally
        {
            isLoading = false;
        }
    }

    private List<TaskItem> GetFilteredTasks(string status)
    {
        var query = allTasks.Where(t => t.Status == status);

        if (!string.IsNullOrWhiteSpace(searchTerm))
        {
            query = query.Where(t => t.Title.Contains(searchTerm, StringComparison.OrdinalIgnoreCase));
        }

        return query.ToList();
    }

    private void OnSearchChanged(string term)
    {
        searchTerm = term;
    }

    private async Task MoveTask(int taskId, string newStatus)
    {
        try
        {
            await TaskService.UpdateTaskStatusAsync(taskId, newStatus);
            // Update local state to avoid a full reload
            var task = allTasks.FirstOrDefault(t => t.Id == taskId);
            if (task is not null)
            {
                allTasks = allTasks
                    .Select(t => t.Id == taskId ? t with { Status = newStatus } : t)
                    .ToList();
            }
        }
        catch (Exception ex)
        {
            errorMessage = ex.Message;
        }
    }

    private async Task CreateTask(
        (string Title, string Assignee, string Priority, DateTime DueDate) args,
        string status)
    {
        try
        {
            var created = await TaskService.CreateTaskAsync(args.Title, args.Assignee, args.Priority, args.DueDate);
            // CreateTaskAsync returns a task with default status; ensure it matches the column
            var taskWithStatus = created with { Status = status };
            allTasks.Add(taskWithStatus);
        }
        catch (Exception ex)
        {
            errorMessage = ex.Message;
        }
    }
}

