@* A single Kanban column showing its tasks and an optional add-task form *@

<div class="col">
    <div class="card h-100">
        <div class="card-header d-flex justify-content-between align-items-center">
            <strong>@ColumnName</strong>
            <span class="badge bg-secondary">@Tasks.Count</span>
        </div>
        <div class="card-body p-2" style="overflow-y: auto;">
            @foreach (var task in Tasks)
            {
                <TaskCard Task="task"
                          ShowMoveLeft="ShowMoveLeft"
                          ShowMoveRight="ShowMoveRight"
                          OnMoveLeftClicked="OnMoveLeftClicked"
                          OnMoveRightClicked="OnMoveRightClicked" />
            }

            @if (ShowAddForm)
            {
                <AddTaskForm Status="@Status"
                             OnSave="OnAddTaskSave"
                             OnCancel="OnAddTaskCancel" />
            }
        </div>
        <div class="card-footer p-2">
            @if (!ShowAddForm)
            {
                <button class="btn btn-outline-primary btn-sm w-100" @onclick="ToggleAddForm">
                    + Add Task
                </button>
            }
        </div>
    </div>
</div>

@code {
    [Parameter, EditorRequired] public string ColumnName { get; set; } = default!;
    [Parameter, EditorRequired] public string Status { get; set; } = default!;
    [Parameter] public List<TaskItem> Tasks { get; set; } = new();
    [Parameter] public bool ShowMoveLeft { get; set; }
    [Parameter] public bool ShowMoveRight { get; set; }
    [Parameter] public EventCallback<int> OnMoveLeftClicked { get; set; }
    [Parameter] public EventCallback<int> OnMoveRightClicked { get; set; }
    [Parameter] public EventCallback<(string Title, string Assignee, string Priority, DateTime DueDate)> OnTaskCreated { get; set; }

    private bool ShowAddForm;

    private void ToggleAddForm() => ShowAddForm = true;

    private async Task OnAddTaskSave((string Title, string Assignee, string Priority, DateTime DueDate) newTask)
    {
        await OnTaskCreated.InvokeAsync(newTask);
        ShowAddForm = false;
    }

    private void OnAddTaskCancel() => ShowAddForm = false;
}

