+        searchTerm = term;
+    }
+
+    private async Task MoveTask(int taskId, string newStatus)
+    {
+        try
+        {
+            await TaskService.UpdateTaskStatusAsync(taskId, newStatus);
+            // Update local state to avoid a full reload
+            var task = allTasks.FirstOrDefault(t => t.Id == taskId);
+            if (task is not null)
+            {
+                allTasks = allTasks
+                    .Select(t => t.Id == taskId ? t with { Status = newStatus } : t)
+                    .ToList();
+            }
+        }
+        catch (Exception ex)
+        {
+            errorMessage = ex.Message;
+        }
+    }
+
+    private async Task CreateTask(
+        (string Title, string Assignee, string Priority, DateTime DueDate) args,
+        string status)
+    {
+        try
+        {
+            var created = await TaskService.CreateTaskAsync(args.Title, args.Assignee, args.Priority, args.DueDate);
+            // CreateTaskAsync returns a task with default status; ensure it matches the column
+            var taskWithStatus = created with { Status = status };
+            allTasks.Add(taskWithStatus);
+        }
+        catch (Exception ex)
+        {
+            errorMessage = ex.Message;
+        }
+    }
+}
